def main():
    """Main entry point."""
    parser = argparse.ArgumentParser(description="OpenClaw Agent Spawner")
    parser.add_argument("--spawn", "-s", help="Spawn agent: format 'agent_id:agent_type:command'")
    parser.add_argument("--kill", "-k", help="Kill agent by ID")
    parser.add_argument("--kill-all", action="store_true", help="Kill all agents")
    parser.add_argument("--list", "-l", action="store_true", help="List running agents")
    parser.add_argument("--work-dir", "-d", default=".", help="Working directory for agents")
    args = parser.parse_args()

    spawner = AgentSpawner()

    if args.spawn:
        parts = args.spawn.split(":")
        if len(parts) != 3:
            logger.error("Invalid format. Use: agent_id:agent_type:command")
            sys.exit(1)
        agent_id, agent_type, command = parts
        result = spawner.spawn_agent(agent_id, agent_type, command, args.work_dir)
        if result:
            print(f"Spawned: {result}")
        else:
            print("Failed")
            sys.exit(1)

    elif args.kill:
        if spawner.shutdown_agent(args.kill):
            print(f"Killed: {args.kill}")
        else:
            print(f"Failed: {args.kill}")
            sys.exit(1)

    elif args.kill_all:
        spawner.shutdown_all()
        print("All shutdown")

    elif args.list:
        print(f"{'Agent ID':<20} {'Type':<15} {'Port':<8}")
        print("-" * 50)
        with spawner._lock:
            for aid, data in spawner.agents.items():
                cfg = data["config"]
                print(f"{aid:<20} {cfg.agent_type:<15} {cfg.port:<8}")
        if not spawner.agents:
            print("No agents")

    else:
        parser.print_help()


if __name__ == "__main__":
    main()
